UPDATE public.garden_import_queue SET
  payload = '{"species": "Coconut", "species_slug": "coconut", "varieties": [{"name": "Malayan Dwarf (All Colors)", "slug": "malayan-dwarf-all-colors", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Malaysia, introduced late 1800s", "traits": "Medium-sized tree (30-60 feet), compact growth, early bearing in 3-4 years. Available in Yellow, Green, Golden/Orange, and Red varieties based on fruit color.", "flesh_fruit": "", "yield_notes": "60-100 nuts per year once established", "growing_notes": "Suitable for Humid subtropical subtropical climate with protection. Requires warm, sheltered position, free-draining soil, and deep organic mulch. Resistant to Lethal Yellowing disease. Best planted in coastal locations; will tolerate temperatures to -3°C but unlikely to fruit south of northern NSW.", "availability": "Daley''s Fruit Tree Nursery (Queensland), Oxley Nursery humid subtropical climates, specialized palm nurseries"}, {"name": "Dwarf Hybrid (Solomon Islands selection)", "slug": "dwarf-hybrid-solomon-islands-selection", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Solomon Islands, with some selections from North Queensland", "traits": "High-yielding precocious hybrid, flowers in 3rd year, fruits in 4th year in moist tropical conditions. Moderate-sized fruit with large volume-to-husk ratio.", "flesh_fruit": "", "yield_notes": "High productivity once established", "growing_notes": "Will grow outside the tropics in warm, sheltered position. Worth trying in coastal locations as far south as Coffs Harbour, NSW. Requires free-draining soil and deep organic mulch. Suitable for Humid subtropical warmer suburbs with frost protection.", "availability": "Daley''s Fruit Tree Nursery (Queensland)"}, {"name": "Maypan Hybrid", "slug": "maypan-hybrid", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Jamaica, 1960s (Malayan Dwarf × Panama Tall)", "traits": "Medium-sized tree to 60 feet, cold-hardy for a coconut, disease-resistant especially to Lethal Yellowing. Combines hardiness of Malayan Dwarf with weather resistance of Panama Tall.", "flesh_fruit": "", "yield_notes": "Good productivity, 80-100 nuts per year", "growing_notes": "", "availability": ""}, {"name": "Fiji Dwarf", "slug": "fiji-dwarf", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Fiji, selected for disease resistance in 1970s", "traits": "Unique dwarf with swollen bole at base, slower-growing, distinctive thick crooked trunk, compact height to 25 feet. Shorter, wider leaflets create fuller canopy.", "flesh_fruit": "", "yield_notes": "Moderate, 50-70 nuts per year", "growing_notes": "Selected for resistance to Lethal Yellowing disease. Suitable for humid subtropical climates with protection, especially in warmer coastal suburbs. Compact size makes harvesting easier. Requires warm microclimate and frost protection.", "availability": "Specialty palm nurseries"}, {"name": "Native Niu Kafa Type (Historical)", "slug": "native-niu-kafa-type-historical", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Indigenous to Australia, documented in historical records from Four Mile Beach Port Douglas (1908), Russell Island, and other Queensland coastal areas", "traits": "Tall upright crown shape (distinct from spreading niu vai varieties). Long, angular three-sided nuts with thick husk adapted for oceanic dispersal. Some dwarf phenotypes exist with unique Australian characteristics.", "flesh_fruit": "", "yield_notes": "Variable, generally lower than cultivated varieties", "growing_notes": "", "availability": ""}, {"name": "Panama Tall (Pacific Tall)", "slug": "panama-tall-pacific-tall", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Panama/Pacific region", "traits": "Large tree to 100 feet, exceptional hardiness and cold tolerance for coconut. Most cold-resistant variety available. Excellent wind resistance.", "flesh_fruit": "", "yield_notes": "80-100 nuts per year", "growing_notes": "", "availability": ""}, {"name": "West Coast Tall (WCT)", "slug": "west-coast-tall-wct", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "Indigenous to India, cultivated since ancient times along west coast", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Kuttiyadi (WCT Ecotype)", "slug": "kuttiyadi-wct-ecotype", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Kuttiyadi region, Kozhikode District, tropical monsoon climates - ecotype of West Coast Tall", "traits": "Tall palm adapted to hilly midland regions, distinct genetic makeup from other WCT due to local environmental factors (climate, pH, rainfall). Matures in 5 years (faster than standard WCT).", "flesh_fruit": "", "yield_notes": "Higher nut yield than standard WCT", "growing_notes": "Indigenous tropical monsoon climates ecotype adapted to midland regions with different environmental conditions than coastal WCT. Developed over generations through natural selection in Kuttiyadi''s specific terroir. Represents local agrobiodiversity. Excellent for tropical monsoon climates area which is inland.", "availability": "tropical monsoon climates Agricultural University, regional nurseries in Kozhikode/Calicut area"}, {"name": "East Coast Tall (ECT)", "slug": "east-coast-tall-ect", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "East coast of India (Tamil Nadu, Andhra Pradesh, Odisha)", "traits": "Tall variety 50-90 feet, thrives in well-drained sandy loam, alluvial and red loamy soils. Distinct orange color on young nuts. Tolerates inland conditions better than WCT.", "flesh_fruit": "", "yield_notes": "60-70 nuts per year, starts bearing 6-8 years", "growing