  payload = '{"species": "Grapes", "species_slug": "grapes", "varieties": [{"name": "Carlos", "slug": "carlos", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "North Carolina State University, 1970", "traits": "Bronze-skinned, small berries (15-20mm), self-fertile, perfect flowers, vigorous vine", "flesh_fruit": "Sweet, juicy with distinctive fruity flavor, less musky than traditional muscadines", "yield_notes": "High yielding, 4-8 tons per acre, uniform ripening", "growing_notes": "Excellent subtropical adaptation. Self-fertile eliminates need for pollinizer. Intermediate tolerance to bitter rot, powdery mildew, angular leaf spot. Susceptible to black rot and Pierce''s disease in high pressure areas. Thrives in warm humid climates, performs exceptionally well in humid subtropical climates conditions. Requires minimal spraying.", "availability": "Available from Australian nurseries including Daleys Fruit, subtropical specialist nurseries"}, {"name": "Noble", "slug": "noble", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "North Carolina State University, 1971", "traits": "Black-purple berries, medium size, excellent disease resistance, self-fertile", "flesh_fruit": "Rich, sweet, less musky flavor than typical muscadines, excellent for fresh eating", "yield_notes": "High yields, uniform berry ripening, consistent production", "growing_notes": "Most popular red muscadine for wine and juice. Self-fertile, excellent for Humid subtropical humid climate. High disease resistance to major fungal diseases. Flavor less musky than traditional muscadines making it excellent for fresh consumption. Ideal for coastal subtropical gardens. Performs well without intensive spray programs.", "availability": "Daleys Fruit Trees (exclusive Australian distributor), subtropical fruit nurseries"}, {"name": "Southern Home", "slug": "southern-home", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "University of Florida, 1994", "traits": "Black berries, small to medium clusters (12 berries average), unique maple-shaped leaves, ornamental qualities", "flesh_fruit": "Unique aromatic flavor different from typical muscadine, rated moderate to more than acceptable by consumer panels", "yield_notes": "Everbearing - produces ripe fruit from mid-August to October/November, extended harvest period", "growing_notes": "Interspecific hybrid (muscadine × bunch grape). Highly tolerant to fungal diseases (ripe rot, bitter rot, black rot, anthracnose, downy mildew). No Pierce''s disease symptoms observed. Excellent subtropical adaptation. Ornamental qualities with distinctive leaf shape. Regular fungicide/insecticide programs typically not needed. Propagates readily from herbaceous cuttings. Perfect for Humid subtropical hot humid climate.", "availability": "Available through specialized subtropical nurseries, may require importation"}, {"name": "Fry", "slug": "fry", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "University of Florida release", "traits": "Very large bronze grapes (20-25mm), female flowers require pollinizer", "flesh_fruit": "Sweet, juicy, delicious with distinctive fruity flavor", "yield_notes": "Moderate yield and vigor, extended ripening period (6 weeks from first to last harvest)", "growing_notes": "", "availability": ""}, {"name": "Magnolia", "slug": "magnolia", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Mississippi release", "traits": "Bronze berries, self-fertile, perfect flowers", "flesh_fruit": "Sweet, aromatic, traditional muscadine flavor", "yield_notes": "Good yields, reliable production", "growing_notes": "", "availability": ""}, {"name": "Scuppernong 🏆", "slug": "scuppernong", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Native variety, cultivated since 1500s", "traits": "Large bronze-green berries, thick skin characteristic of muscadines", "flesh_fruit": "Sweet, distinctive musky flavor, traditional southern taste", "yield_notes": "Variable yields depending on growing conditions", "growing_notes": "", "availability": ""}, {"name": "Chambourcin", "slug": "chambourcin", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "France (Joannes Seyve), available since 1963", "traits": "Deep colored, medium berries, teinturier (red juice), vigorous productive vine", "flesh_fruit": "Black cherry, red fruit, herbaceous notes, black pepper, chocolate undertones. Medium body with modest tannins.", "yield_notes": "Very productive, 4-5 tons per year (can reach 7-8 tons with management), 11-17 tons per hectare", "growing_notes": "French-American interspecific hybrid. Excellent resistance to fungal diseases, especially downy mildew. Thrives in warm, humid environments - ideal for humid subtropical climates. Used successfully in Queensland''s South Burnett and coastal NSW Hunter Valley. High tolerance to diseases caused by humidity. Works particularly well in subtropical climates. Can be used for table grapes or wine. Heavy cropper of rich flavorsome grapes when fully ripe. Excellent for backyards in humid climates.", "availability": "Daleys Fruit Trees, Australian subtropical nurseries, widely available in QLD"}, {"name": "Isabella 🏆", "slug": "isabella", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "America (South Carolina), pre-1816, cultivated 200+ years", "traits": "Round, black grapes, seedy, softer downy leaf undersides typical of labrusca, vigorous vine", "flesh_fruit": "Seedy but delicious, rich sweet flavor, fragrant", "yield_notes": "Huge crops, very productive, late mid-season ripening", "growing_notes": "", "availability": ""}, {"name": "Iona", "slug": "iona", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "America (Dr. Grant), first fruited 1864", "traits": "Reddish clusters, medium berries", "flesh_fruit": "Exquisitely tasty: rich, sweet, mellow. One of the finest flavored labrusca varieties.", "yield_notes": "Good yields when netted from birds", "growing_notes": "Quality table grape prized for flavor. Less deeply dissected leaves typical of labrusca. Skins slip easily from fruit. Humidity resistant. Heritage variety worth preserving. Requires bird protection as fruit is highly attractive. Suitable for subtropical Queensland.", "availability": "Limited availability, heritage grape specialists, may require grafting from collectors"}, {"name": "Concord 🏆", "slug": "concord", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "USA (Massachusetts), 1849, Ephraim Wales Bull", "traits": "Large, round, blue-black grapes, slip-skin, hardy", "flesh_fruit": "Classic ''grape'' flavor, sweet when fully ripe", "yield_notes": "Reliable production", "growing_notes": "Most famous American grape, parent of many hybrids. Disease resistant, hardy. Can grow in subtropical climates. Performs better than many vinifera in humidity. Traditional variety.", "availability": "May be available through specialty nurseries, quarantine restrictions to QLD"}, {"name": "Niagara", "slug": "niagara", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "USA (New York), 1868", "traits": "Large, white/greenish grapes, slip-skin", "flesh_fruit": "Sweet, aromatic, foxy labrusca character", "yield_notes": "Good yields", "growing_notes": "White labrusca variety. Many labrusca varieties once present in Australia have vanished from cultivation. Niagara may still be found in pockets kept by CSIRO or home gardeners. Disease resistant qualities valuable for subtropical climates.", "availability": "CSIRO collection, rare in commercial availability"}, {"name": "Delaware", "slug": "delaware", "lineage_type": "heirloom", "climate_slug": "humid-s