  payload = '{"species": "Hyssop", "species_slug": "hyssop", "varieties": [{"name": "Hyssopus officinalis (Standard Blue)", "slug": "hyssopus-officinalis-standard-blue", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Southern Europe, Mediterranean (cultivated since ancient times, 1000+ years)", "traits": "Upright subshrub, 50cm tall, woody base, dark green aromatic leaves 2-2.5cm long", "flesh_fruit": "", "yield_notes": "Moderate to high, can be harvested 2-3 times per season", "growing_notes": "Best performer for humid subtropical climates subtropical climate. Tolerates warm temperatures but prefers afternoon shade in peak summer. Does NOT like high humidity - plant in well-draining raised beds. Drought-tolerant once established. Prune after flowering. May struggle during humid wet summers.", "availability": "The Seed Collection, Succeed Heirlooms Australia, Daley''s Fruit Tree Nursery"}, {"name": "''Blue Flower''", "slug": "blue-flower", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "European cultivar selection, pre-1900s", "traits": "Similar to standard blue, 50-60cm, compact habit", "flesh_fruit": "", "yield_notes": "High flowering, good leaf production", "growing_notes": "Selected for superior flowering. Suitable for humid subtropical climates with good drainage and air circulation. Plant in full sun to part shade. Susceptible to fungal issues in high humidity - ensure excellent drainage.", "availability": "International heirloom seed suppliers"}, {"name": "''Caeruleus''", "slug": "caeruleus", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "European selection, modern cultivar", "traits": "Compact plant 60cm tall, gray-green foliage, dense habit", "flesh_fruit": "", "yield_notes": "Good, compact size means less space required", "growing_notes": "Compact size good for humid subtropical climates gardens with limited space. Requires excellent drainage. Benefits from afternoon shade in summer. Gray-green foliage more drought-tolerant. Not ideal for prolonged humid periods.", "availability": "Specialty nurseries, international suppliers"}, {"name": "''Sissinghurst''", "slug": "sissinghurst", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "England, named after Sissinghurst Castle Garden", "traits": "Dwarf variety 30cm tall, large bright green leaves, compact mounding habit", "flesh_fruit": "", "yield_notes": "Moderate, smaller plant = less total harvest but good leaf-to-flower ratio", "growing_notes": "Excellent for humid subtropical climates container growing and small gardens. Lower height reduces wind damage. Good for edging. Needs very good drainage. Bright foliage more susceptible to sunburn - provide afternoon shade.", "availability": "Beth Chatto Gardens (UK), specialty international suppliers"}, {"name": "Hyssopus officinalis f. albus (White Hyssop)", "slug": "hyssopus-officinalis-f-albus-white-hyssop", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Natural form, Southern Europe, cultivated for centuries", "traits": "50-60cm tall, dark green leaves, slightly more upright than blue form", "flesh_fruit": "", "yield_notes": "Similar to standard blue variety, good leaf and flower production", "growing_notes": "", "availability": ""}, {"name": "''Alba''", "slug": "alba", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "European white cultivar selection", "traits": "Compact 60cm, dark green foliage, bushy habit", "flesh_fruit": "", "yield_notes": "Good, compact plants produce well", "growing_notes": "Selected for improved white flower form. Good for humid subtropical climates with proper care. Plant in raised beds with excellent drainage. Benefits from organic mulch to keep roots cool in summer heat. Prune hard in spring.", "availability": "North Car