  payload = '{"species": "Kiwi", "species_slug": "kiwi", "varieties": [{"name": "Vincent", "slug": "vincent", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "China, developed for subtropical climates", "traits": "Medium-sized fruit, egg-shaped, fuzzy brown skin, vigorous vine growth, excellent low-chill variety", "flesh_fruit": "Bright green flesh, sweet tropical flavor, medium size (80-100g), excellent eating quality", "yield_notes": "High productivity, produces large crops consistently", "growing_notes": "EXCELLENT FOR humid subtropical climates - Only 100-200 chill hours required. Thrives in warm subtropical climates. Tolerates high humidity. Pairs with Tomuri male pollinator. Well-suited to Humid subtropical mild winters and warm summers. Disease resistant.", "availability": "Available from Queensland and NSW nurseries, Daleys Fruit Tree Nursery"}, {"name": "Sweetie (Daleys Selection)", "slug": "sweetie-daleys-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Australia, selected by Daleys Nursery from golden kiwi seedling, 2000s", "traits": "Small to medium fruit, vigorous hardy growth, specifically bred for subtropical Queensland", "flesh_fruit": "Yellow-green flesh, sweet flavor, smooth texture", "yield_notes": "Good yields in subtropical conditions", "growing_notes": "EXCELLENT FOR humid subtropical climates - Very low chill requirement specifically selected for subtropics. Perfect for humid subtropical climates gardens. Australian-bred for local conditions. Requires specific male pollinator also from Daleys.", "availability": "Daleys Fruit Tree Nursery, Kyogle NSW"}, {"name": "Hayward Seedling (Queensland Selection)", "slug": "hayward-seedling-queensland-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Queensland, Australia, selected as Hayward seedling adapted to warmer climates, 1990s", "traits": "Similar to Hayward but slightly smaller, more elongated shape, adapted to warmer winters", "flesh_fruit": "Light-green flesh, good flavor, typical fuzzy brown skin", "yield_notes": "Productive in Queensland conditions", "growing_notes": "EXCELLENT FOR humid subtropical climates - Relatively low chill requirement compared to standard Hayward. Originated in Queensland, well-adapted to humid subtropical climates climate. Handles humid subtropical conditions better than traditional Hayward.", "availability": "Queensland specialist nurseries, Daleys"}, {"name": "Elmwood", "slug": "elmwood", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "New Zealand, developed for low-chill regions", "traits": "Extremely vigorous growth, large showy fragrant blossoms, very large fruit (up to 280g/10 oz)", "flesh_fruit": "Green flesh, excellent flavor, extremely large kiwi-shaped fruits", "yield_notes": "Very high yields, bears fruit at young age (200-260 lbs per mature vine)", "growing_notes": "", "availability": ""}, {"name": "Abbott", "slug": "abbott", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "New Zealand, early selection from Chinese germplasm, 1920s-1930s", "traits": "Early flowering and maturing, medium-sized round fruit, densely hairy brown skin", "flesh_fruit": "Light-green flesh, very sweet taste, lower ascorbic acid, medium titratable acidity", "yield_notes": "Good yields, productive", "growing_notes": "", "availability": ""}, {"name": "Dexter", "slug": "dexter", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Australia/California, developed by Dr. David Dexter, 1970s", "traits": "Medium size, slightly elongated, quite hairy, compact growth habit", "flesh_fruit": "Green flesh, good flavor, sweet tropical taste", "yield_notes": "Good production, early ripening", "growing_notes": "", "availability": ""}, {"name": "Blake", "slug": "blake", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "New Zealand, HortResearch breeding program, 1990s", "traits": "Small to medium fruit, teardrop-shaped, early maturing (6-8 weeks before Hayward)", "flesh_fruit": "Golden-brown smooth skin, juicy sweet flesh, slightly more acidic than Hayward", "yield_notes": "Precocious variety, bears fruit one year earlier than other varieties, heavy yields", "growing_notes": "SUITABLE FOR humid subtropical climates - Low-chill requirement. Very early ripening perfect for areas with early autumn frosts. Partially self-fruitful. Vigorous disease-resistant vines. Good storage capacity. Flowers very early. Excellent for extending harvest season.", "availability": "Specialty nurseries, limited in Australia"}, {"name": "Allison", "slug": "allison", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "New Zealand, chance seedling discovered 1920s, named after Alexander Allison", "traits": "Medium-sized oblong fruit, densely hairy brownish skin, early maturing", "flesh_fruit": "Light-green flesh, good flavor, good balance of sweetness and acidity", "yield_notes": "Good yields, reliable producer", "growing_notes": "", "availability": ""}, {"name": "Bruno", "slug": "bruno", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "New Zealand, named after Bruno Just, early nurseryman, 1930s-1940s", "traits": "Large elongated cylindrical fruit, dark brown skin with short dense hairs", "flesh_fruit": "Light-green flesh, good flavor, higher ascorbic acid content than Abbott", "yield_notes": "Very vigorous, produces large crops", "growing_notes": "", "availability": ""}, {"name": "Saanichton 12", "slug": "saanichton-12", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Vancouver Island, British Columbia, Canada, developed for coastal climate, 1980s", "traits": "Medium-large fruit, vigorous growth, cold-hardy in mild climates", "flesh_fruit": "Sweet good-tasting fruit, typical green flesh", "yield_notes": "Productive, reliable cropping", "growing_notes": "", "availability": ""}, {"name": "Issai", "slug": "issai", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Japan, 1980s", "traits": "Small grape-sized fruit, smooth hairless skin, less vigorous than other kiwiberries (12-20 feet)", "flesh_fruit": "Green flesh, very sweet flavor similar to regular kiwi, kumquat-sized", "yield_notes": "Starts cropping in 2nd year, productive", "growing_notes": "SUITABLE FOR humid subtropical climates - Self-fertile (hermaphrodite flowers) - no male needed! Prefers filtered light in SE Queensland. Grows well under 30% shade cloth. Less vigorous makes it perfect for smaller humid subtropical climates gardens or containers. Hardy to Zone 5 but tolerates subtropical heat.", "availability": "Fruit Tree Cottage (SE Queensland), Australian nurseries"}, {"name": "Tomuri (Male)", "slug": "tomuri-male", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "New Zealand", "traits": "Late-blooming male, cream-colored flowers in June, strong vigorous grower", "flesh_fruit": "", "yield_notes": "One male can pollinate up to 8 female vines", "growing_notes": "EXCELLENT FOR humid subtropical climates - Very low chill requirement (100 hours). Perfect match for Vincent. Extended bloom duration covers late-flowering females. Essential for subtropical low-chill plantings. Requires summer pruning due to vigor.", "availability": "Queensland nurseries, widely available"}, {"name": "Matua (Male)", "slug": "matua-male", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "New Zealand", "traits": "Early to mid-season blooming, large heart-shaped fuzzy foliage, burgundy shoots, vigorous", "flesh_fruit": "", "yield_not