UPDATE public.garden_import_queue SET
  payload = '{"species": "Lemon", "species_slug": "lemon", "varieties": [{"name": "Eureka Lemon", "slug": "eureka-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "California, USA (1858), derived from Sicilian seeds, introduced to Australia 1824", "traits": "Medium-small, elliptical fruit with short neck and nipple. Bright yellow, slightly textured rind with sunken oil glands. Virtually thornless tree, 4-6m height, spreading habit.", "flesh_fruit": "Pale greenish-yellow flesh, highly acidic, very juicy. Low seed count (0-5 seeds). Classic tart lemon flavor ideal for culinary use.", "yield_notes": "Highly productive, bears fruit almost year-round in humid subtropical climates. Main crop winter, with smaller spring/summer crops. Precocious bearer.", "growing_notes": "Best citrus for most areas of Australia. Thrives in Humid subtropical subtropical climate with year-round production. Fruit borne outside canopy, requires wind protection. Less cold tolerant than Lisbon but excellent for humid subtropical conditions. Easy picking due to thornless branches.", "availability": "Widely available at Queensland nurseries including Bunnings, Daley''s Fruit Tree Nursery, and local garden centers."}, {"name": "Taylor Eureka", "slug": "taylor-eureka", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Australia - nucellar selection from Sydney, NSW (1955)", "traits": "Improved Eureka clone with enhanced vigor. Medium-sized tree, thornless, everbearing nature.", "flesh_fruit": "Similar to standard Eureka - highly acidic, juicy, low-seeded fruit. Consistent fruit quality.", "yield_notes": "More productive than standard Eureka with better crop efficiency. Year-round production.", "growing_notes": "One of the most popular commercial clones in Australia. Excellent for Humid subtropical subtropical climate. More disease resistant than older Eureka selections. Compatible with Benton citrange, Rough lemon, and sweet orange rootstocks.", "availability": "Available through specialized citrus nurseries in Queensland."}, {"name": "Lambert Eureka", "slug": "lambert-eureka", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Australia - nucellar selection from NSW (1956)", "traits": "Another improved Eureka clone, vigorous growth, spreading habit.", "flesh_fruit": "Classic Eureka characteristics - acidic, juicy, excellent flavor.", "yield_notes": "High yielding, consistent production throughout year.", "growing_notes": "Equally popular as Taylor in Australian commercial production. Well-adapted to Humid subtropical warm, humid conditions. Better management characteristics than older selections.", "availability": "Specialized Queensland citrus nurseries."}, {"name": "Lisbon Lemon", "slug": "lisbon-lemon", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Portugal, introduced to Australia from Lisbon, multiple introductions to USA and Australia", "traits": "Large tree (up to 6m), vigorous, thorny, densely foliaged, upright growth habit. Fruit produced inside canopy providing wind/sun protection.", "flesh_fruit": "Elliptical to oblong fruit with moderate nipple. Yellow, slightly rough rind. Greenish-yellow flesh, very high juice content, very acidic. Fewer than 9 seeds.", "yield_notes": "Prolific bearer. Main crop winter/early spring in subtropical humid subtropical climates. Most resistant to heat and adverse conditions.", "growing_notes": "Hardier than Eureka with greater cold AND heat tolerance. Excellent for Humid subtropical hot summers. Fruit quality better than Eureka due to interior canopy production protecting from wind damage. More cold tolerant but thrives equally well in subtropical heat. Thorny nature makes harvesting more difficult but provides natural pest protection.", "availability": "Widely available throughout Queensland nurseries."}, {"name": "Prior Lisbon", "slug": "prior-lisbon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Australian selection - early-fruiting Lisbon variety", "traits": "Similar to standard Lisbon but earlier maturity. Thorny, vigorous, upright habit.", "flesh_fruit": "Identical fruit characteristics to Lisbon - highly acidic, juicy.", "yield_notes": "Fruits earlier in season than standard Lisbon, extending harvest period.", "growing_notes": "Better choice for humid subtropical climates than standard Lisbon due to earlier cropping. Excellent heat and humidity tolerance. Preferred Melbourne alternative now used successfully in humid subtropical climates.", "availability": "Available through specialist citrus nurseries in Queensland."}, {"name": "Meyer Lemon (Improved)", "slug": "meyer-lemon-improved", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "China, discovered near Beijing (1908) by Frank Meyer, introduced to Narara NSW (1944). Improved virus-free clone developed later.", "traits": "Compact tree 2.5-3m, nearly thornless, round fruit (not true lemon - lemon × mandarin hybrid). Dark yellow-orange rind when ripe, thin smooth skin.", "flesh_fruit": "Deep yellow tender pulp, much lower acid than true lemons, sweeter flavor, 5-10 seeds. Juicier and less acidic than Eureka/Lisbon.", "yield_notes": "Main crop winter with some spring through summer cropping. Productive but less than Eureka.", "growing_notes": "", "availability": ""}, {"name": "Lemonade Lemon (Lemonade)", "slug": "lemonade-lemon-lemonade", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Arrived humid subtropical climates from Pacific Islands (mid-1980s)", "traits": "Thorny tree, compact growth suitable for small spaces. Multiple fruiting periods per year.", "flesh_fruit": "Extremely mild acid profile - can be eaten like a mandarin. Sweet enough to eat fresh as a citrus fruit rather than typical sour lemon.", "yield_notes": "Fruits multiple times per year in Humid subtropical subtropical climate.", "growing_notes": "", "availability": ""}, {"name": "Villa Franca (Villafranca)", "slug": "villa-franca-villafranca", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Sicily, Italy, imported to USA (1875), introduced to Australia. Nucellar clone selected at Narara (1959).", "traits": "Belongs to Eureka group, tree closer to Lisbon in appearance but less upright and less thorny. Can grow to 8m but usually smaller.", "flesh_fruit": "Fruit similar to Eureka - few seeds, quite acidic. Smooth skin, juicy flesh.", "yield_notes": "Mainly winter cropper, but in Queensland produces significant summer crop with correct management (early harvesting, irrigation, nitrogen nutrition).", "growing_notes": "Popular in Queensland specifically for summer fruiting potential. Late season cropper complementing other varieties. Susceptible to rind breakdown in hot conditions. More commonly grown in Queensland than other Australian states due to subtropical climate encouraging summer production.", "availability": "Available at Queensland specialty citrus nurseries."}, {"name": "Fino Lemon (Primofiori)", "slug": "fino-lemon-primofiori", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Spain (Murcia region), imported to Australia for evaluation. Also known as Mesero in Spain.", "traits": "Vigorous, somewhat thorny, tree habit similar to Eureka. Noted for smooth rind texture.", "flesh_fruit": "Nice shaped fruit, smooth textured rind. Low seed number (average 5 seeds). High quality external appearance.", "yield_notes": "Matures similar time to Eureka. Consistent heavy crops, tends to out-yield Eureka. Produces several smaller crops at Gosford NSW.", "growing_notes": "Imported with aim of producing high quality fruit suitable for export September-November. Quick to mature. Elite budwood becoming more available for humid subtropical climates home gardeners. Performs well in Australian subtropical trials.", "availability": "Limited but increasing availability through specialist Queensland nurseries."}, {"name": "Verna Lemon", "slug": "verna-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Spain, imported from Morocco to Australia", "traits": "Large spreading productive tree, thornless. Late season cropper.", "flesh_fruit": "Virtually seedless. Tender pulp, good acid content. Less juice than Eureka but excellent quality. Medium-thick rind main crop, thinner in subsequent crops.", "yield_notes": "Main crop late winter/spring in Southern Australia. Multiple crops throughout year in coastal NSW. Second crop (''Secundus'') of inferior quality.", "growing_notes": "", "availability": ""}, {"name": "Yen Ben Lemon", "slug": "yen-ben-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "New Zealand, planted Burrum Heads Queensland (late 1930s), commercially grown New Zealand since 1991", "traits": "Bush-like appearance when laden with fruit. Darker, thicker leaves than typical lemon. Precocious bearer.", "flesh_fruit": "Smaller fruit than Eureka (120-130g). Smooth textured thin rind. High quality external appearance and juice content. Juice maintained with proper long-term storage.", "yield_notes": "Good production levels. Main winter crop with smaller intermediate crops.", "growing_notes": "Minor commercial plantings in Australia. Under evaluation in variety trials. High juice content and smooth rind appealing characteristics. Originally planted in Queensland indicating regional suitability.", "availability": "Limited availability, specialty citrus nurseries in Queensland."}, {"name": "Bush Lemon (Rough Lemon)", "slug": "bush-lemon-rough-lemon", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Naturalized in subtropical Australia, grows wild in Queensland bushland", "traits": "Good sized tree, small thorns. Bumpy, thick-skinned fruit ranging yellow to orange coloring. Wild, rugged appearance. Very hardy.", "flesh_fruit": "Thick skin with true lemon flavor. Low juice content but iconic citrus taste. Seeds present, mildly sour flavor. Good for zest.", "yield_notes": "Moderate production, frost-free zones only.", "growing_notes": "Preferred lemon for Australian lemon butter/curd. Easy to grow, naturally adapted to Humid subtropical subtropical conditions. Wild form demonstrates excellent humidity and heat tolerance. Leaves make delicious tea. Often used as rootstock for grafting due to vigor and disease resistance.", "availability": "Grows wild, can be sourced from specialized native/heritage plant nurseries in Queensland or propagated from wild specimens."}, {"name": "Ponderosa Lemon", "slug": "ponderosa-lemon", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "USA, chance seedling discovered 1880s, launched commercially 1900. Hybrid of citron × pomelo (not true lemon).", "traits": "Dwarf to medium tree (2-4m suitable for humid subtropical climates gardens), thorny, purple-tinged flowers and new growth. Suitable for pots.", "flesh_fruit": "Massive grapefruit-sized fruit (2-4 pounds), thick bumpy rind. Extremely acidic juice similar to true lemon. Many seeds. Pale yellow-green flesh.", "yield_notes": "Year-round flowering and fruiting. High productivity of enormous fruits.", "growing_notes": "Ornamental value with impressive fruits that can remain on tree for months. Less cold-hardy than true lemons but excellent for Humid subtropical warm climate. Mainly grown as ornamental in California/Florida. Fruit can substitute measure-for-measure for regular lemons. Enough juice in one fruit for several lemon pies. Ideal for humid subtropical climates container growing.", "availability": "Available at Queensland specialty nurseries and online suppliers."}, {"name": "Bearss Lemon", "slug": "bearss-lemon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Florida USA, selected 1952 from seedling planted 1892 in Bearrs Grove, Lutz. Originally called ''Sicily''.", "traits": "Vigorous, thornless to nearly thornless tree. Fast grower, tends to produce water sprouts.", "flesh_fruit": "Very juicy, high-acid fruit. High levels of lemon oil in rind. Fewer seeds, tarter and more sour than other varieties. High-grade juice.", "yield_notes": "Abundant fruit production July through December. More productive than many citrus varieties.", "growing_notes": "Excellent for juicing and baking due to high oil content. Strong growth rate and near-thornless nature makes maintenance easier. Good adaptation to subtropical conditions. Available on dwarf rootstocks suitable for humid subtropical climates gardens.", "availability": "Available through Queensland citrus specialty suppliers."}, {"name": "Genoa Lemon (Genova)", "slug": "genoa-lemon-genova", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Italian origin, like Villafranca. Recently becoming available in Australia.", "traits": "Smaller tree habit than Eureka/Lisbon. Fewer and smaller thorns on fruiting branches.", "flesh_fruit": "Classic lemon characteristics, high quality fruit.", "yield_notes": "Good production levels for smaller tree size.", "growing_notes": "", "availability": ""}, {"name": "Kagzi Nimbu (Kargzi Lime) 🌏", "slug": "kagzi-nimbu-kargzi-lime", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Vikram (Acid Lime)", "slug": "vikram-acid-lime", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Recently identified high-yielding cultivar for India", "tr