flesh_fruit": "", "yield_notes": "High yielding. Good commercial production.", "growing_notes": "", "availability": "Hawaiian variety. May be available through specialized Indian importers or agricultural research institutions. Tested in Indian conditions."}, {"name": "Nelmak 2 (Nelspruit Macadamia 2)", "slug": "nelmak-2-nelspruit-macadamia-2", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "South Africa, Nelspruit ARC 1973. Nelspruit Agricultural Research Council selection. Named Nelspruit Makadamia in Afrikaans.", "traits": "Vigorous prolific grower. Fragrant pink flowers. Nuts hang in clusters. Beautiful ornamental.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Macadamia integrifolia Seedling 🌱", "slug": "macadamia-integrifolia-seedling", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "🌏 INDIGENOUS - Native Queensland/NSW Australia. Wild genetic diversity.", "traits": "Evergreen tree 10-20m tall. Smooth-margined mature leaves (juvenile leaves serrated). Whorls of 3 leaves. Cream-white flowers. Green new growth. Smooth spherical shells.", "flesh_fruit": "", "yield_notes": "Variable. Takes 10-12 years seed to production (vs 4-6 years grafted). Some produce well, others minimal. Unpredictable.", "growing_notes": "", "availability": ""}, {"name": "Macadamia tetraphylla Seedling 🌱", "slug": "macadamia-tetraphylla-seedling", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "🌏 INDIGENOUS - Native Gold Coast to Northern NSW Australia. Bush Nut. Wild genetic diversity.", "traits": "Evergreen tree up to 20m. Four spiny serrated leaves per whorl (vs 3 for integrifolia). Pink flowers. Pink/maroon new growth. Rough pebbled shells. Better cold tolerance than integrifolia.", "flesh_fruit": "", "yield_notes": "Variable. 10-12 years seed to production. Some productive, others minimal. Unpredictable yields