  payload = '{"species": "Potato", "species_slug": "potato", "varieties": [{"name": "White Star", "slug": "white-star", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Improved variety, widely adapted", "traits": "Determinate type, medium to large oval tubers, white skin, shallow eyes", "flesh_fruit": "White, floury texture, dry when cooked", "yield_notes": "High yield potential under winter conditions", "growing_notes": "TOP CHOICE for humid subtropical climates subtropics. Determinate growth means single layer tubers, no hilling required. Performs excellently planted July-August. Widely recommended by subtropical gardeners. Good disease resistance.", "availability": "Australian seed potato suppliers, humid subtropical climates nurseries"}, {"name": "Sebago", "slug": "sebago", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "USA (Maine), 1938. Cross of Chippewa × Katahdin. Arrived Victoria 1940", "traits": "Long to oval shape, creamy-white skin, shallow eyes, uniform size", "flesh_fruit": "White, medium starch, fluffy texture", "yield_notes": "25-30 t/ha, 130 days maturity", "growing_notes": "Australia''s most popular variety. Excellent all-rounder for subtropics. Originally developed for late blight resistance. Suitable for boiling, mashing, roasting, baking, chips. Very versatile and widely available. Good storage life.", "availability": "All Australian supermarkets and nurseries, certified seed widely available"}, {"name": "Desiree", "slug": "desiree", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Netherlands, 1962", "traits": "Oval shape, smooth pink/red skin, fleet eyes", "flesh_fruit": "Pale yellow, firm waxy texture", "yield_notes": "Good yielder, reliable performer", "growing_notes": "Excellent all-rounder for humid subtropical climates. Suitable for roasting, mashing, baking. Holds shape well. One of Australia''s favorite potatoes. Performs well in subtropical conditions. Good for multiple uses.", "availability": "Widely available Australian supermarkets, Queensland nurseries"}, {"name": "Kennebec", "slug": "kennebec", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "USA, 1940s. Determinate variety", "traits": "Large, shallow eyes, white skin, tubers form high on stem", "flesh_fruit": "White, firm texture", "yield_notes": "High yield potential, 250mm spacing recommended", "growing_notes": "", "availability": ""}, {"name": "Coliban", "slug": "coliban", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Australia, bred for Australian conditions", "traits": "Medium to late season, round to oval, white skin", "flesh_fruit": "White, floury texture", "yield_notes": "Good cropping, reliable", "growing_notes": "Australian-bred variety. Good all-rounder for mashing, baking, roasting, French fries. Widely grown commercially. Suitable for subtropical growing. Available fresh markets.", "availability": "Australian supermarkets, commercial seed suppliers"}, {"name": "Pink Eye (Tasmanian Pink Eye)", "slug": "pink-eye-tasmanian-pink-eye", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Australia (Tasmania), dating back to 1880s-1940s. Heirloom variety", "traits": "Round to oval, cream/mauve skin with distinctive pink/purple eyes. Determinate type", "flesh_fruit": "Creamy yellow, waxy texture", "yield_notes": "Early maturing (70-110 days)", "growing_notes": "EXCELLENT heritage variety for subtropics. Tasmania''s favorite potato. Fast-growing determinate type (10-13 weeks). Perfect for boiling, baking, salads. Holds shape well. Popular variety across Australia. Good for new potatoes. Available certified seed.", "availability": "Tassie Seed Potatoes, Australian nurseries, specialty suppliers"}, {"name": "Kipfler", "slug": "kipfler", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Austria (heritage variety). Known as German Finger Potato or Austrian Crescent", "traits": "Fingerling type, long cigar-shaped, light brown to dusty yellow skin. Determinate", "flesh_fruit": "Golden yellow, waxy, smooth texture", "yield_notes": "High yielding, good storage life", "growing_notes": "One of Australia''s most popular fingerling varieties. Nutty, buttery flavor. Excellent for salads, roasting, boiling, steaming. Fast growing determinate (10-13 weeks) suitable for subtropics. Holds shape when cooked. Highly valued by chefs.", "availability": "Australian farmers markets, specialty nurseries, humid subtropical climates suppliers"}, {"name": "Dutch Cream", "slug": "dutch-cream", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Netherlands, old heritage variety", "traits": "Smooth pale yellow skin, shallow eyes, oval shape", "flesh_fruit": "Rich yellow, waxy, firm, creamy texture", "yield_notes": "Mid-season, 90-110 days, good yields", "growing_notes": "", "availability": ""}, {"name": "Nicola", "slug": "nicola", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Germany, widely grown in Europe", "traits": "Oval shaped, beige-yellow skin, cream colored", "flesh_fruit": "Yellow, waxy texture, buttery", "yield_notes": "Good all-rounder yields", "growing_notes": "Perfect all-rounder with sweet nutty flavor. Excellent for mashing, gnocchi, boiling, baking, salads, roasting. Indeterminate type. Very versatile. Popular in Australian markets.", "availability": "Australian supermarkets, humid subtropical climates markets, nurseries"}, {"name": "Pontiac (Red Pontiac)", "slug": "pontiac-red-pontiac", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "USA, widely grown", "traits": "Round shape, bright red thin skin, deep eyes. Determinate", "flesh_fruit": "White, moist", "yield_notes": "Good yielder", "growing_notes": "Popular waxy red potato. Excellent for boiling, roasting, baking, salads. Doesn''t darken after cooking. Determinate fast grower (10-13 weeks). Good for subtropical conditions. Small commercial production in Australia.", "availability": "Australian seed suppliers, specialty nurseries"}, {"name": "Russet Burbank", "slug": "russet-burbank", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "USA, 1850s-1906. Descendant of Early Rose variety developed by Luther Burbank", "traits": "Large, elongated, rough dark brown russet skin, deep eyes", "flesh_fruit": "White, dry, high starch, floury", "yield_notes": "High yields under proper conditions", "growing_notes": "World''s #1 French fry potato. Australia''s restaurant standard for wedges. Heritage variety. Excellent for baking, chips. Most popular variety in North America. Can grow in subtropics but prefers cooler conditions. Commercial variety in Tasmania.", "availability": "The Seed Collection, Australian specialty suppliers, limited supermarket availability"}, {"name": "Spunta", "slug": "spunta", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Netherlands", "traits": "Large oval shape, smooth yellow skin, shallow eyes. Determinate", "flesh_fruit": "Creamy yellow", "yield_notes": "Good yields", "growing_notes": "Versatile all-rounder. Good for boiling, baking, mashing, microwaving, deep-frying. Determinate fast grower (10-13 weeks) ideal for subtropics. Widely grown commercially in Queensland.", "availability": "Australian markets, Queensland commercial suppliers"}, {"name": "King Edward", "slug": "king-edward", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "UK, 1902. Classic heritage variety", "traits": "Cream skin with pink markings, smooth", "flesh_fruit": "Creamy white, floury texture", "yield_notes": "Good yields", "growing_notes": "Classic British heritage potato. Gorgeous masher and fluffy roaster. Good for baking. Indeterminate type. Can be grown in subtropics with care. Available from heritage suppliers.", "availability": "Diggers Club, heritage potato suppliers, Australian specialty nurseries"}, {"name": "Otway Red", "slug": "otway-red", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Australia", "traits": "Smooth skinned, dark red skin", "flesh_fruit": "Creamy flesh", "yield_notes": "Good performer", "growing_notes": "Australian variety. Excellent mashed, roasted, fried. Grown in SE Queensland with success. Some sources report red varieties can struggle in warmer climates, but Otway Red adapted.", "availability": "Australian nurseries, Queensland suppliers"}, {"name": "Bintje", "slug": "bintje", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Netherlands, old heritage variety", "traits": "Smooth pale yellow skin, shallow eyes, mid-season (90-110 days)", "flesh_fruit": "Pale yellow, waxy firm, fine creamy texture", "yield_notes": "High yielding, widely adaptable, stores well", "growing_notes": "Excellent for salads, frying, boiling, roasting. Long shelf life. Dutch heritage variety introduced to Australia in 1990s. Gourmet variety. Good adaptability.", "availability": "Australian specialty markets, gourmet suppliers"}, {"name": "Pink Fir Apple", "slug": "pink-fir-apple", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 15, "origin": "France/Netherlands, 1850. Over 100 years cultivation history", "traits": "Unusual long knobby banana/cigar shape, pink skin", "flesh_fruit": "Light yellow/cream, waxy, firm", "yield_notes": "Late season fingerling", "growing_notes": "Classic heirloom fingerling. Excellent for salads, roasting, boiling, baking. Too dry for roasting alone. Holds shape well. Available Australian nurseries. Indeterminate type.", "availability": "The Lost Seed, heritage suppliers, Australian specialty nurseries"}, {"name": "Royal Blue", "slug": "royal-blue", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 16, "origin": "Netherlands, gourmet variety", "traits": "Blue/purple skin", "flesh_fruit": "White flesh", "yield_notes": "Good yields", "growing_notes": "All-rounder variety. Introduced to Australia 1990s. Boosted fresh market. Good general purpose potato.", "availability": "Australian specialty markets"}, {"name": "Bismarck", "slug": "bismarck", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 17, "origin": "Germany, introduced to Tasmania 1880s. Historic Australian variety", "traits": "Early maturing, long oval, creamy white tubers, purple eyes", "flesh_fruit": "Creamy white", "yield_notes": "Good yields, early harvest", "growing_notes": "Historic variety grown in Tasmania/north-west Australia since 1880s. Ideal for boiling as new potato. Makes great chips when mature. Crispy potato skins. Popular in early 1900s.", "availability": "Heritage Fruits Society, Tasmanian suppliers, heritage collections"}, {"name": "Purple Congo", "slug": "purple-congo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 18, "origin": "South America, specialty variety", "traits": "Purple skin, determinate type", "flesh_fruit": "Purple flesh, dry texture", "yield_notes": "Good yields", "growing_notes": "Specialty purple variety. Steam, boil, or mash. Too dry for roasting. Floury type. Determinate fast grower suitable for subtropics. Unique color.", "availability": "Australian specialty nurseries, farmers markets"}, {"name": "Atlantic", "slug": "atlantic", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 19, "origin": "USA, processing variety", "traits": "Round to oval, white skin", "flesh_fruit": "White flesh", "yield_notes": "Commercial production yields", "growing_notes": "Main processing variety for crisps in Australia. Grown commercially in Queensland and other states. Good chip-making variety. Available as seed.", "availability": "Commercial seed suppliers, some nurseries"}, {"name": "Kufri Surya", "slug": "kufri-surya", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "India (CPRI, Shimla), 2005. Developed from International Potato Centre, Lima, Peru germplasm", "traits": "Early maturing (80-90 days), oblong tubers, white smooth skin", "flesh_fruit": "Pale yellow flesh", "yield_notes": "20-25 t/ha, moderate to high", "growing_notes": "", "availability": ""}, {"name": "Kufri Lima", "slug": "kufri-lima", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "India (CPRI) in collaboration with International Potato Center (CIP)", "traits": "Early maturing, heat and disease resistant", "flesh_fruit": "Good quality", "yield_notes": "23.5-36.6 t/ha depending on harvest time. Very high for heat conditions", "growing_notes": "", "availability": ""}, {"name": "Kufri Khyati", "slug": "kufri-khyati", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "India (CPRI, Shimla)", "traits": "Heat tolerant variety", "flesh_fruit": "Good table quality", "yield_notes": "30.2 t/ha at 75 days in trials. High yielding", "growing_notes": "", "availability": ""}, {"name": "Kufri Jyoti", "slug": "kufri-jyoti", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "India (CPRI), 1968. Cross of 3069d(4) × 2814 Q(1)", "traits": "Large oval, white skin, fleet eyes, small swift eyes", "flesh_fruit": "White flesh", "yield_notes": "20 t/acre (50 t/ha), 90-100 days maturity", "growing_notes": "Widely cultivated across India including Karnataka (peninsular region near tropical monsoon climates). Moderately resistant to early and late blight. Suitable for processing. Grown in Bihar, Maharashtra, Gujarat, Haryana, Punjab, Uttar Pradesh, West Bengal. Can adapt to warmer climates.", "availability": "Widely available Indian seed suppliers, tropical monsoon climates agricultural stores"}, {"name": "Kufri Chandramukhi", "slug": "kufri-chandramukhi", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "India (CPRI), 1968. Early maturing", "traits": "Large, round to oval, white skin, slightly flattened eyes", "flesh_fruit": "Dull white flesh", "yield_notes": "25-30 t/ha, 80-90 days maturity", "growing_notes": "", "availability": ""}, {"name": "Kufri Sindhuri", "slug": "kufri-sindhuri", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "India (CPRI), 1966. Cross of Kufri Kundan × Kufri Red", "traits": "Medium sized, round, red skin, deep eyes", "flesh_fruit": "Dull white flesh", "yield_notes": "40 t/ha (120 qtl/acre), 110-120 days", "growing_notes": "", "availability": ""}, {"name": "Kufri Badshah", "slug": "kufri-badshah", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "India (CPRI), 1980. Cross of Kufri Jyoti × Kufri Alankar", "traits": "Large to medium, red, round, medium deep eyes", "flesh_fruit": "White flesh, tasty with good flavor", "yield_notes": "40-50 t/ha (130 qtl/acre), 100-110 days", "growing_notes": "Released for Indo-gangetic plains and Plateau region of Peninsular India. Moderately resistant to early blight. Resistant to Potato Virus Y (PVY). Tolerant to frost and late blight. Good table quality. Grown in Jammu Kashmir, Haryana, Punjab, Gujarat, Uttar Pradesh, Madhya Pradesh.", "availability": "Indian seed suppliers, available in south India"}, {"name": "Kufri Bahar", "slug": "kufri-bahar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "India (CPRI), 1980. Cross of Kufri Red × Ginek", "traits": "White, large, round to oval, deep eyes. Slow degeneration rate", "flesh_fruit": "White flesh", "yield_notes": "45 t/ha (100-120 qtl/acre), 100-110 days", "growing_notes": "Released for plains of Haryana, Punjab, Western Uttar Pradesh. Very good keeper (10-12% weight loss). Resistant to late blight, early blight, leaf roll. Suitable for diverse culinary applications.", "availability": "Northern Indian suppliers, tropical monsoon climates via dealers"}, {"name": "Kufri Pukhraj", "slug": "kufri-pukhraj", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 8, "origin": "India (CPRI), 1998. Cross of Craig''s Defiance × JEX/B-687", "traits": "Large, oval, slightly tapered, white skin, fleet eyes", "flesh_fruit": "Yellow flesh, low dry matter (16.1%)", "yield_notes": "40 t/ha (160 qtl/acre), 70-90 days", "growing_notes": "Widely adaptable variety. Resistant to early blight, moderately resistant to late blight. Suitable for table purposes. Grown in Maharashtra, Orissa, Uttar Pradesh, Bihar, Gujarat, Haryana, Himachal Pradesh, Punjab, Madhya Pradesh, West Bengal. Very good keeper. High water use efficiency.", "availability": "Available across India including tropical monsoon climates region"}, {"name": "Kufri Ashoka", "slug": "kufri-ashoka", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 9, "origin": "India (CPRI), 1996. Cross of (EM/C-1020 × Allerfrüheste Gelbe)", "traits": "Early variety, large oval-long, white skin, fleet eyes", "flesh_fruit": "White flesh", "yield_notes": "40 t/ha, 70-80 days maturity", "growing_notes": "Widely adaptable variety. Released to replace Kufri Chandramukhi. Suitable for short day conditions. Grown in Bihar, Haryana, Punjab, Uttar Pradesh, West Bengal. Susceptible to late blight. Table purpose.", "availability": "Indian seed suppliers, tropical monsoon climates agricultural centers"}, {"name": "Kufri Lauvkar", "slug": "kufri-lauvkar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 10, "origin": "India (CPRI). Developed for warm climates", "traits": "Large, round, white skin, fleet eyes. Early tuberization in warm climates", "flesh_fruit": "White flesh", "yield_notes": "30 t/ha, fast maturing (75-80 days)", "growing_notes": "EXCELLENT for warm climate regions like tropical monsoon climates. Able to build yields rapidly under warmer climate. Primarily cultivated in Maharashtra, Madhya Pradesh, Karnataka. Perfect for processing into chips. Heat-tolerant characteristics.", "availability": "Southern India suppliers, Karnataka/tropical monsoon climates dealers"}, {"name": "Kufri Jawahar", "slug": "kufri-jawahar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 11, "origin": "India (CPRI), 1996. Cross of Kufri Neelamani × Kufri Jyoti", "traits": "Medium round-oval, creamy white skin, fleet eyes", "flesh_fruit": "Pale yellow flesh", "yield_notes": "40 t/ha, 80-90 days maturity", "growing_notes": "Early maturing variety suitable for intensive cropping systems. Moderately resistant to late blight. Grown in Gujarat, Haryana, Madhya Pradesh, Punjab, Karnataka (southern region). Table purpose variety.", "availability": "Available in Karnataka and surrounding southern states including tropical monsoon climates"}, {"name": "Kufri Chipsona-1", "slug": "kufri-chipsona-1", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 12, "origin": "India (CPRI), 1998. Developed for processing", "traits": "Medium to large, oval, white skin, fleet eyes", "flesh_fruit": "Dull white flesh, high dry matter (9.8%)", "yield_notes": "40 t/ha (170-180 qtl/acre), 90-110 days", "growing_notes": "Primarily for making chips and French fries. Resistant to late blight, tolerant to frost. Grown mainly in Bihar and Uttar Pradesh. Excellent keeper. Higher germination percentage. Highest dry matter production suitable for processing industry.", "availability": "Northern India suppliers, available through tropical monsoon climates dealers"}, {"name": "Kufri Chipsona-3", "slug": "kufri-chipsona-3", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 13, "origin": "India (CPRI). Processing variety", "traits": "Less sucrose content", "flesh_fruit": "High dry matter (21.7%)", "yield_notes": "165-175 qtl/acre", "growing_notes": "Suitable for making chips. Recommended for Northern Telangana Zone, can be grown in southern regions. Late wilt disease doesn''t occur. Good processing quality.", "availability": "Processing industry suppliers, southern India dealers"}, {"name": "HT/7-1329 (Advanced Heat Tolerant Hybrid)", "slug": "ht-7-1329-advanced-heat-tolerant-hybrid", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 14, "origin": "India (ICAR-CPRI). Advanced heat tolerant breeding line", "traits": "Heat tolerant, good plant vigor", "flesh_fruit": "Good quality, high dry matter", "yield_notes": "23.4-35.6 t/ha depending on harvest time. Outstanding under heat stress", "growing_notes": "", "availability": ""}, {"name": "HT/10-2002 (Heat Tolerant Hybrid)", "slug": "ht-10-2002-heat-tolerant-hybrid", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 15, "origin": "India (ICAR-CPRI). Advanced heat tolerant line", "traits": "Heat tolerant characteristics", "flesh_fruit": "Good quality", "yield_notes": "25 t/ha in tropical monsoon climates trials", "growing_notes": "", "availability": ""}, {"name": "Kufri Kiran", "slug": "kufri-kiran", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 16, "origin": "India (ICAR-CPRI). Heat-tolerant table variety", "traits": "Early planting capability (15-20 days earlier than normal)", "flesh_fruit": "Table quality", "yield_notes": "11% higher tuber yield than other heat-tolerant varieties", "growing_notes": "Developed for subtropical North Indian plains and plateau regions. Can be planted earlier in season. Suitable for main season in plateau regions. Good heat tolerance characteristics.", "availability": "CPRI dealers, northern and central India suppliers"}, {"name": "Kufri Pushkar", "slug": "kufri-pushkar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 17, "origin": "India (CPRI), 2006. Medium maturing", "traits": "White tubers, medium maturing", "flesh_fruit": "Low dry matter (17.4%), table purpose", "yield_notes": "160-170 qtl/acre, 90-100 days", "growing_notes": "Excellent keeper (lowest total weight loss 7.7%). Late wilt disease resistant. Can be stored in normal conditions. Higher germination percentage. Suitable for table purposes. Good marketable yield.", "availability": "Indian seed suppliers nationwide"}, {"name": "Chinese Potato (Plectranthus rotundifolius) - Koorka 🌏 INDIGENOUS", "slug": "chinese-potato-plectranthus-rotundifolius-koorka-indigenous", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 18, "origin": "Indigenous to tropical monsoon climates. Known as ''Koorka'' in Malayalam", "traits": "Small tubers, harder than Irish potato, aromatic", "flesh_fruit": "Unique taste and aroma, desired shape", "yield_notes": "Variable, monsoon crop", "growing_notes": "", "availability": ""}], "variety_count": 39}'::jsonb,
