UPDATE public.garden_import_queue SET
  payload = '{"species": "Soursop", "species_slug": "soursop", "varieties": [{"name": "Seedling Selections (Queensland-Adapted)", "slug": "seedling-selections-queensland-adapted", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Queensland, Australia (grown from diverse tropical seed sources)", "traits": "Heart-shaped fruits, dark green skin with soft fleshy spines, fruit size 10-30cm long, weight 1.5-4kg", "flesh_fruit": "White, juicy, slightly fibrous, creamy texture with sweet-tart flavor combining strawberry, pineapple and citrus notes", "yield_notes": "12-24 fruits per tree annually, fruit production begins 2-3 years from seed in tropical conditions, 3-5 years in subtropics", "growing_notes": "Requires frost-free site with protection from cold winds. In Queensland, well-watered trees reach 4.5-5.5m in 6-7 years. Fruiting season begins April. Sensitive to temperatures below 5°C when young, requiring protection until established. Main pest is mealybug on fruits. Prefers deep, well-drained, semi-dry soil.", "availability": "Daley''s Fruit Tree Nursery, Fruitopia Nursery humid subtropical climates, Ross Creek Tropicals Gympie, Sunshine Coast nurseries"}, {"name": "Grafted Kyogle Selection", "slug": "grafted-kyogle-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Kyogle, New South Wales, Australia (subtropical selection)", "traits": "Medium-large fruit, heart-shaped, green skin, proven performer in marginal subtropical climate", "flesh_fruit": "White, juicy with sweet lemony taste (not sour like lemon), firm texture, less fibrous than seedlings", "yield_notes": "Good crop production, multiple fruits per season, bears within 2-3 years of grafting", "growing_notes": "", "availability": ""}, {"name": "Golden/Yellow Soursop Selection", "slug": "golden-yellow-soursop-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Rare selection available in Australian subtropical nurseries", "traits": "Large fruit, golden-yellow when ripe (distinguishing feature), spiny green skin that yellows at maturity", "flesh_fruit": "Sweet and aromatic, perfect blend of tropical fruits with berry hint, less acidic than standard green varieties", "yield_notes": "Good producer with proper care, typical soursop yield range", "growing_notes": "", "availability": ""}, {"name": "Smooth Flesh Selection", "slug": "smooth-flesh-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Queensland selection grown from smooth-fleshed variety", "traits": "Heart-shaped fruit, typical rough green skin with soft spines", "flesh_fruit": "Notable for smoother, less fibrous flesh texture, juicy and slightly acid, creamy consistency", "yield_notes": "Standard soursop productivity", "growing_notes": "Seedling selection specifically chosen for superior flesh texture. Excellent for fresh consumption and processing. Superb when pureed with vanilla ice cream. Requires subtropical to tropical climate with frost protection.", "availability": "Daley''s Fruit Tree Nursery"}, {"name": "Giant South American Selection", "slug": "giant-south-american-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "South American seed-grown selection", "traits": "Large conical fruits, typically 7kg+, specimens exceeding 10kg possible on established trees", "flesh_fruit": "Firm, white, less fibrous than other commercially available varieties", "yield_notes": "Large individual fruit size compensates for typical soursop shy-bearing habit", "growing_notes": "", "availability": ""}, {"name": "Sunshine Coast Grafted Selection", "slug": "sunshine-coast-grafted-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Sunshine Coast, Queensland selection", "traits": "Heart-shaped fruit, rough green skin with soft fleshy spines", "flesh_fruit": "Juicy, slightly acid, producing rich creamy thirst-quenching juice", "yield_notes": "Good cropping history in Sunshine Coast conditions", "growing_notes": "", "availability": ""}, {"name": "Mountain Soursop (Annona montana)", "slug": "mountain-soursop-annona-montana", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Central and South America, naturalized in various tropical regions", "traits": "Round fruit with pale green-yellow skin when ripe, less spiky than regular soursop, fruit 10-15cm diameter", "flesh_fruit": "Lemon-colored, smooth flesh with milder flavor than regular soursop, somewhat inferior quality but acceptable", "yield_notes": "Produces within 2-3 years from seed, reliable bearer", "growing_notes": "MUCH HARDIER than regular soursop - tolerates temperatures down to -2°C, making it the BEST CHOICE for marginal humid subtropical climates areas. Will tolerate more cold than Annona muricata and can be used as rootstock for grafting regular soursop in colder regions. Adaptable to wide range of soils and dry conditions. Can grow in full sun or part shade, reaching 8m height.", "availability": "Daley''s Fruit Tree Nursery, specialist subtropical nurseries"}, {"name": "Mullatha / Mullu Chakka (Indian Common) 🌏", "slug": "mullatha-mullu-chakka-indian-common", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "Indigenous to South India, widely cultivated in tropical monsoon climates, Tamil Nadu, Karnataka, Andhra Pradesh", "traits": "Large oval to heart-shaped fruits, dark green leathery skin with soft protruding spines, fruit weight 2-6kg", "flesh_fruit": "White, creamy, fibrous segments surrounding pithy core, sweet-sour flavor with musky aroma, contains 30-200 black seeds", "yield_notes": "Continuous flowering and fruiting, main season April-October in India, 12-24 fruits per tree", "growing_notes": "", "availability": ""}, {"name": "Sweet Type (Sirsak Ratu - Indonesian influence)", "slug": "sweet-type-sirsak-ratu-indonesian-influence", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Southeast Asian selection, cultivated in tropical monsoon climates through historical trade connections", "traits": "Small to medium fruit, few-seeded, typically 1-2kg", "flesh_fruit": "Sub-acid flavor (lower acidity), sweeter than common types, preferred for fresh eating", "yield_notes": "Moderate productivity, fewer but sweeter fruits", "growing_notes": "Similar to sweet types grown in Indonesia and Philippines. Predominant in a few tropical monsoon climates localities. Best for fresh consumption. Excellent adaptation to tropical monsoon conditions with high humidity during fruit set. Thrives in Tropical monsoon warm temperatures (21-32°C).", "availability": "Specialty tropical monsoon climates nurseries, inquire at local fruit tree sellers"}, {"name": "Aguinaldo Type (Philippine Introduction)", "slug": "aguinaldo-type-philippine-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "Philippines, introduced to India through tropical fruit exchange programs", "traits": "Medium fruit approximately 1kg, yellow-green peel", "flesh_fruit": "Juicy, sub-acid (moderately acidic), 78% of fruit weight is edible, approximately 70 seeds per fruit", "yield_notes": "Good edible portion ratio, reliable cropper in tropical conditions", "growing_notes": "Part of Philippines'' major soursop production heritage (Western Visayas, Central Luzon leading regions). Adapted to similar tropical monsoon climate as tropical monsoon climates. Sub-acid types excellent for both fresh consumption and processing. Can be consumed fresh or used for juices and desserts.", "availability": "May be available through specialty importers or agricultural research stations in tropical monsoon climates"}, {"name": "Davao Type (Philippine Introduction)", "slug": "davao-type-philippine-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "Davao region, Philippines", "traits": "Larger fruit approximately 1.7kg, light green peel", "flesh_fruit": "Moderately juicy, pleasantly sub-acid, 82% of fruit weight is edible, approximately 82 seeds per fruit", "yield_notes": "Excellent edible portion (82%), good size fruit, reliable bearer", "growing_notes": "Higher edible percentage than Aguinaldo type. Philippines is major producer with similar tropical climate to tropical monsoon climates. Mindanao region (including Davao) known for quality soursop. Excellent for Tropical monsoon climate with high temperatures and humidity. Pleasant sub-acid flavor makes it versatile for fresh eating and processing.", "availability": "May be available through specialty importers or agricultural research stations in tropical monsoon climates"}, {"name": "Seedling Selections (Kerala-Adapted)", "slug": "seedling-selections-kerala-adapted", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "Local tropical monsoon climates selections from superior mother trees", "traits": "Variable, ranging from round to heart-shaped to angular, skin color from dark green to yellow-green at maturity", "flesh_fruit": "Quality varies from soft and juicy to firm and dry, flavor ranges from sweet to sub-acid to acid", "yield_notes": "Variable but adapted to local conditions, fruits within 2-3 years", "growing_notes": "tropical monsoon climates has diverse soursop genetic material grown on limited scale. Trees grow wild and cultivated in Southern India. Excellent adaptation to tropical monsoon climate. Thrives on coastal regions with tropical weather. Prefers well-drained, loamy soil with high humidity during fruit set. Continuous flowering with main season April-October.", "availability": "Local tropical monsoon climates nurseries, home garden exchanges, Greens of tropical monsoon climates, Golden Hills Farm"}, {"name": "Crioula (Brazilian Introduction) 🏆", "slug": "crioula-brazilian-introduction", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "Brazil - traditional variety with 100+ year history", "traits": "Variable fruit size, traditional Brazilian landrace characteristics", "flesh_fruit": "Traditional flavor profile, pulp properties vary within acceptable range for cultivar", "yield_notes": "Reliable production in tropical conditions", "growing_notes": "", "availability": ""}, {"name": "Blanca (Brazilian Introduction)", "slug": "blanca-brazilian-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "Brazil", "traits": "''Blanca'' refers to white flesh characteristic, distinguishing feature from cultivar name", "flesh_fruit": "Notable white flesh quality, good pulp characteristics", "yield_notes": "Differs from other Brazilian varieties in size, shape, and yield characteristics", "growing_notes": "", "availability": ""}, {"name": "FAO II (Brazilian Introduction)", "slug": "fao-ii-brazilian-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "Brazil - variety from FAO agricultural development programs", "traits": "Selected for specific commercial characteristics including fruit size and shape", "flesh_fruit": "Pulp properties optimized for commercial production and processing", "yield_notes": "Selected for improved productivity characteristics", "growing_notes": "Developed through FAO agricultural programs for tropical fruit improvement. Represents improved germplasm with enhanced commercial characteristics. Well-suited to tropical monsoon climate with high humidity and rainfall patterns similar to tropical monsoon climates.", "availability": "May be available through agricultural research institutions or FAO programs"}, {"name": "Lisa (Brazilian Introduction)", "slug": "lisa-brazilian-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 8, "origin": "Brazil - ''Lisa'' means ''smooth'' in Portuguese, referring to texture characteristics", "traits": "Selected for smoother skin or flesh characteristics", "flesh_fruit": "Notable smooth texture, reduced fibrousness compared to other varieties", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Morada (Brazilian Introduction)", "slug": "morada-brazilian-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 9, "origin": "Brazil - ''Morada'' means ''dwelling/residence'' in Portuguese, traditional variety name", "traits": "Traditional Brazilian variety with distinct characteristics", "flesh_fruit": "Pulp properties differ significantly from other main Brazilian varieties", "yield_notes": "Yield characteristics vary from Crioula, Blanca, FAO II, and Lisa", "growing_notes": "", "availability": ""}, {"name": "Guanaba Azucaron (Central American Sweet) 🏆", "slug": "guanaba-azucaron-central-american-sweet", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 10, "origin": "El Salvador - traditional sweet variety (''azucaron'' means ''sugary'' in Spanish)", "traits": "Sweet type fruit, lower acidity than acid types", "flesh_fruit": "Sweet (relatively low acid), excellent for fresh consumption and drinks", "yield_notes": "Typical soursop production levels", "growing_notes": "", "availability": ""}, {"name": "Guanabana Dulce (Dominican Sweet) 🏆", "slug": "guanabana-dulce-dominican-sweet", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 11, "origin": "Dominican Republic - traditional sweet variety (''dulce'' means ''sweet'' in Spanish)", "traits": "Most sought-after variety in Dominican Republic", "flesh_fruit": "Sweet (low acidity in relative sense), excellent flavor for fresh eating", "yield_notes": "Highly valued commercial variety in Dominican production", "growing_notes": "", "availability": ""}, {"name": "Cuban Fiberless (Guanabana Sin Fibre) 🏆", "slug": "cuban-fiberless-guanabana-sin-fibre", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 12, "origin": "Santiago de las Vegas Agricultural Experiment Station, Cuba (1920s-1950s)", "traits": "Medium-sized, yellow-green fruit, distinctive bluish-green foliage", "flesh_fruit": "FIBERLESS or very low fiber content (defining characteristic), smooth texture, less acid than typical varieties", "yield_notes": "Vegetatively propagated clone ensures consistent quality", "growing_notes": "HEIRLOOM STATUS - historic Cuban selection from 1920s-1950s era. Vegetatively propagated superior clone. Distinctive bluish-green foliage allows identification. Fiberless characteristic highly valued for processing and fresh consumption. Cuban agricultural expertise in tropical fruit improvement. Made its way to Florida in 1959. Ideal for Tropical monsoon tropical climate. Excellent for ice cream, smoothies, and juice production due to smooth texture.", "availability": "May be available through Cuban germplasm sources or propagated from existing Cuban Fiberless trees internationally"}, {"name": "Bennett (Costa Rican Selection) 🏆", "slug": "bennett-costa-rican-selection", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 13, "origin": "Costa Rica, 1920 - named for G.S. Bennett, Agricultural Superintendent of United Fruit Company''s Costa Rican Division", "traits": "Large, handsome fruit, described by Dr. Wilson Popenoe as most fruitful tree seen", "flesh_fruit": "Excellent quality, superior characteristics for commercial production", "yield_notes": "Exceptional productivity - most fruitful soursop tree documented in 1920", "growing_notes": "", "availability": ""}, {"name": "Indonesian Selections (Sirsak)", "slug": "indonesian-selections-sirsak", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 14, "origin": "Indonesia - world''s largest soursop producer", "traits": "Diverse selections adapted to Indonesian tropical conditions, variable fruit size and shape", "flesh_fruit": "Sweet-fruited and sour-fruited types available, quality varies by selection", "yield_notes": "Indonesia produces hundreds of thousands of tons annually, indicating excellent productivity", "growing_notes": "Indonesia is world''s TOP soursop producer with optimal growing conditions. Major production regions: Java, Sumatra, Bali, Sulawesi, Kalimantan. Tropical climate with fertile volcanic soil creates ideal conditions. Trees propagated using seeds or grafting, with grafted plants offering earlier fruiting. Extensive post-harvest handling expertise. Climate highly similar to tropical monsoon climates - tropical, high rainfall, fertile soil. Indonesian cultivation practices directly applicable to tropical monsoon climates production.", "availability": "May be available through Indonesian agricultural institutions or Southeast Asian germplasm exchange"}, {"name": "Thai Selections (Thurian Thet/Thurian Khaek)", "slug": "thai-selections-thurian-thet-thurian-khaek", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 15, "origin": "Thailand", "traits": "Thai selections adapted to Southeast Asian tropical conditions", "flesh_fruit": "Used extensively in Thai desserts, ice creams, and beverages", "yield_notes": "Produced primarily for domestic consumption and regional export", "growing_notes": "", "availability": ""}, {"name": "Malaysian Selections (Durian Belanda)", "slug": "malaysian-selections-durian-belanda", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 16, "origin": "Malaysia", "traits": "Malaysian selections with tropical adaptation", "flesh_fruit": "Quality characteristics suited to fresh consumption and processing", "yield_notes": "Contributes to regional production, smaller scale than Indonesia", "growing_notes": "Malaysia grows soursop on smaller scale than Indonesia but with similar climate advantages. Tropical climate with high humidity and rainfall year-round. Well-drained soil requirements similar to tropical monsoon climates conditions. Southeast Asian cultivation experience valuable for tropical monsoon climates growers. Climate characteristics closely match tropical monsoon climates monsoon patterns.", "availability": "May be available through Malaysian agricultural institutions or regional exchanges"}, {"name": "Vietnamese Selections (Mang Cau Xiem)", "slug": "vietnamese-selections-mang-cau-xiem", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 17, "origin": "Vietnam", "traits": "Vietnamese tropical adaptations", "flesh_fruit": "Quality suited to Vietnamese fresh fruit markets", "yield_notes": "Supports local and regional markets", "growing_notes": "Vietnam cultivates soursop with tropical monsoon climate matching tropical monsoon climates. Strong agricultural sector with tropical fruit expertise. Climate includes distinct wet season with heavy rainfall similar to tropical monsoon climates monsoon. High humidity and warm temperatures year-round. Vietnamese cultivation techniques applicable to tropical monsoon climates conditions.", "availability": "May be available through Vietnamese agricultural institutions"}, {"name": "Mexican Selections (Guanabana)", "slug": "mexican-selections-guanabana", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 18, "origin": "Mexico - world''s leading producer and exporter", "traits": "Diverse selections optimized for commercial production and export, variable fruit sizes", "flesh_fruit": "Quality optimized for frozen pulp production and fresh fruit export", "yield_notes": "Leading world production with advanced cultivation techniques", "growing_notes": "Mexico is WORLD''S LEADING PRODUCER and primary exporter of soursop products (frozen pulp and fresh fruit). Extensive commercial cultivation experience and advanced production techniques. Main season June-September in Mexican growing regions. While some Mexican regions are drier than tropical monsoon climates, coastal tropical areas have similar conditions. Mexican germplasm represents commercial-quality selections with proven export standards. Expertise in post-harvest handling and processing valuable for tropical monsoon climates production development.", "availability": "May be available through Mexican agricultural institutions or major commercial nurseries"}, {"name": "Puerto Rican Selections 🏆", "slug": "puerto-rican-selections", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 19, "origin": "Puerto Rico - 14 distinct types cataloged by Agricultural Experiment Station", "traits": "Wide range cataloged: sweet, sub-acid, and acid types; subdivided by shape (round, heart-shaped, oblong, angular); further classified by flesh consistency (soft/juicy to firm/dry)", "flesh_fruit": "Variable - from soft and juicy to firm and comparatively dry", "yield_notes": "Historical production of 99,790 kg in 1977, indicating significant cultivation", "growing_notes": "", "availability": ""}, {"name": "FIRST CHOICE: Mullatha/Mullu Chakka (indigenous) - perfectly adapted, medicinal value, local availability", "slug": "first-choice-mullatha-mullu-chakka-indigenous-perfectly-adapted-medicinal-value-local-availability", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 20, "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}], "variety_count": 28}'::jsonb,
