UPDATE public.garden_import_queue SET
  payload = '{"species": "Valerian", "species_slug": "valerian", "varieties": [{"name": "1. Common/Garden Valerian - Standard Type", "slug": "1-common-garden-valerian-standard-type", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Europe and Western Asia (naturalized worldwide)", "traits": "Perennial herb to 1.5m tall; pinnately divided leaves; hollow, grooved stems", "flesh_fruit": "", "yield_notes": "", "growing_notes": "POOR adaptability to humid subtropical climates heat/humidity. Prefers cooler climates (zones 4-9). Will struggle in humid subtropical climates summers. May survive as cool-season annual but likely won''t thrive. Requires full sun to part shade, moist soil.", "availability": "Limited in humid subtropical climates. The Seed Collection, Eden Seeds, Succeed Heirlooms (Australian suppliers)"}, {"name": "2. Red Valerian (Centranthus ruber / Valeriana rubra) - Standard", "slug": "2-red-valerian-centranthus-ruber-valeriana-rubra-standard", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Mediterranean region (Portugal, Spain, France, Italy, Greece, North Africa)", "traits": "Multi-stemmed perennial to 80cm; compact, upright growth; blue-green lanceolate leaves", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MODERATE to GOOD adaptability to humid subtropical climates. Mediterranean origin suits warm climates better than V. officinalis. Drought tolerant once established. Heat tolerant. NOT the same as medicinal valerian. Ornamental use only. Can self-seed aggressively - deadhead to control.", "availability": "The Seed Collection (Australia) - available in humid subtropical climates subtropical zones"}, {"name": "3. Red Valerian ''Coccineus''", "slug": "3-red-valerian-coccineus", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Cultivated selection from Mediterranean red valerian", "traits": "Compact form, 60cm tall; darker red flowers than species; blue-green foliage", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MODERATE to GOOD for humid subtropical climates. Heat and drought tolerant. More compact than standard type. Better for hot climates than European valerian. Ornamental only.", "availability": "Specialty nurseries (cultivar selection)"}, {"name": "4. White Valerian (Centranthus ruber ''Albus'')", "slug": "4-white-valerian-centranthus-ruber-albus", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "White-flowered cultivar of Mediterranean red valerian", "traits": "Grows 40-60cm tall; compact perennial; grey-green foliage", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MODERATE to GOOD for humid subtropical climates subtropical conditions. Drought and heat tolerant once established. Performs well in alkaline soils. Ornamental use.", "availability": "The Seed Collection (Australia)"}, {"name": "5. Red Valerian ''Rosenrot''", "slug": "5-red-valerian-rosenrot", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "German cultivar selection", "traits": "Grows to 60cm; intense pink/rose flowers; compact habit", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MODERATE for humid subtropical climates. Heat tolerant Mediterranean genetics. Better than V. officinalis for subtropical conditions.", "availability": "Specialty nurseries (European cultivar)"}, {"name": "6. Valerian ''Lubelski'' (Polish Cultivar)", "slug": "6-valerian-lubelski-polish-cultivar", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Poland (Lublin region), developed 1950s from wild diploid selections; tetraploid form", "traits": "High-yielding thick roots (up to 1kg fresh root/plant); tall stems 1-1.5m; robust growth", "flesh_fruit": "", "yield_notes": "48-90g dry weight per plant (superior to wild types)", "growing_notes": "POOR for humid subtropical climates. Poland''s largest commercial cultivar but bred for cool temperate climates. Will suffer in humid subtropical climates heat/humidity. Best for zones 4-7. Available as certified seed but NOT recommended for subtropical cultivation.", "availability": "Richters (Canada), Incredible Seeds (Canada) - international import only"}, {"name": "7. Valerian ''Polka'' (Polish Cultivar)", "slug": "7-valerian-polka-polish-cultivar", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Poland, thin-rooted variety", "traits": "Thin roots; lower yields than ''Lubelski'' but higher concentration of active compounds", "flesh_fruit": "", "yield_notes": "", "growing_notes": "POOR for humid subtropical climates. Cool climate cultivar. Will not adapt to subtropical heat.", "availability": "Polish gene bank; limited international availability"}, {"name": "8. Valerian ''Norweski'' (Norwegian Type)", "slug": "8-valerian-norweski-norwegian-type", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Norway, Nordic landrace", "traits": "Adapted to short northern growing seasons; cold-hardy", "flesh_fruit": "", "yield_notes": "", "growing_notes": "UNSUITABLE for humid subtropical climates. Extreme cold climate adaptation makes it incompatible with subtropical conditions.", "availability": "Polish/Nordic gene banks only"}, {"name": "9. Valeriana officinalis subsp. sambucifolia", "slug": "9-valeriana-officinalis-subsp-sambucifolia", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Britain (Derbyshire), marshy sites", "traits": "Marsh-adapted ecotype; found on coal measures; diploid wild type", "flesh_fruit": "", "yield_notes": "", "growing_notes": "UNSUITABLE for humid subtropical climates. Requires wet, cool conditions and marshy habitat.", "availability": "Wild collection only (UK)"}, {"name": "10. Valeriana officinalis subsp. collina", "slug": "10-valeriana-officinalis-subsp-collina", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Europe, dry chalk grassland soils", "traits": "Drought-adapted ecotype; smaller plant than marsh types", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MARGINAL for humid subtropical climates. Dry-adapted but still requires cool climate. Alkaline soil tolerance might help.", "availability": "Wild/botanical collection only"}, {"name": "1. Indian Valerian / Tagar (Valeriana jatamansi)", "slug": "1-indian-valerian-tagar-valeriana-jatamansi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "Himalayas (India, Nepal, Pakistan, China); 1200-3000m elevation native range", "traits": "Perennial aromatic herb to 60cm tall; rhizomatous; erect pubescent stems; deeply divided toothed leaves", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MARGINAL to MODERATE for tropical monsoon climates lowlands. Naturally grows at high elevations (cool mountain habitat). May survive in tropical monsoon climates highland areas (Western Ghats) but lowland tropical heat will stress it. Best cultivated at elevation or in cooler seasons. Prefers part shade, moist well-drained soil. Critical traditional medicine plant - endangered from overharvesting.", "availability": "Indian Ayurvedic herb suppliers, traditional medicine markets; cultivation programs in Uttarakhand"}, {"name": "2. Valeriana wallichii (Syn. of V. jatamansi)", "slug": "2-valeriana-wallichii-syn-of-v-jatamansi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Northwestern Himalayas (Kashmir to Bhutan)", "traits": "Now considered synonym of V. jatamansi; historically treated as separate species", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Same cultivation requirements as V. jatamansi. MARGINAL for tropical monsoon climates lowlands, MODERATE for highland cultivation.", "availability": "Ayurvedic suppliers; commercial substitute for European V. officinalis in India"}, {"name": "3. Valeriana hardwickii", "slug": "3-valeriana-hardwickii", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "Eastern Himalayas (Arunachal Pradesh, Mizoram); high altitude species", "traits": "Perennial herb to 150cm; short rhizomes with slender roots; pinnately divided leaves", "flesh_fruit": "", "yield_notes": "", "growing_notes": "UNSUITABLE for tropical monsoon climates lowlands - requires high elevation cool mountain habitat (similar to V. jatamansi). Recently recorded in Phawngpui National Park. Endangered from habitat loss.", "availability": "Very limited; conservation programs in Northeast India"}, {"name": "4. Valeriana hardwickii var. arnottiana", "slug": "4-valeriana-hardwickii-var-arnottiana", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "Northwestern Himalayas (Uttarakhand, Milam region)", "traits": "Regional variety of V. hardwickii; similar growth habit but distinct chemical profile", "flesh_fruit": "", "yield_notes": "", "growing_notes": "UNSUITABLE for tropical monsoon climates. High altitude adaptation only.", "availability": "Research collections only"}, {"name": "5. Red Valerian (Centranthus ruber) - Standard", "slug": "5-red-valerian-centranthus-ruber-standard", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "Mediterranean", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "MODERATE for tropical monsoon climates. Mediterranean species better adapted to heat than European V. officinalis but still prefers drier conditions than tropical monsoon climates monsoon. May succeed in drier winter season (Dec-Feb). Ornamental only, not medicinal. Listed as invasive in South Africa due to aggressive self-seeding.", "availability": "International seed suppliers; not traditional to India"}, {"name": "6. European Valerian (Valeriana officinalis) - NOT RECOMMENDED", "slug": "6-european-valerian-valeriana-officinalis-not-recommended", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "Europe, temperate Asia", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "UNSUITABLE for tropical monsoon climates. Requires cool temperate climate with distinct seasons. Tropical monsoon year-round heat and extreme monsoon humidity will cause plant failure. The species naturally prefers zones 4-9 with cool-weather growing seasons. Heat stress, fungal diseases, and poor root development expected. Use Indian Himalayan species instead.", "availability": "N/A - not recommended for cultivation"}], "variety_count": 16}'::jsonb,
  variety_count = 16
